import { useEffect, useState } from "react";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";

export function RezervacijeRecepcionar() {
    const [rezervacije, setRezervacije] = useState([]);
    const [filterStatus, setFilterStatus] = useState("sve");
    const [novaRezervacija, setNovaRezervacija] = useState({
        datumPocetka: "",
        datumZavrsetka: "",
        idGost: "",
        idSoba: ""
    });
    const [showModal, setShowModal] = useState(false);

    // 🔹 Učitavanje svih rezervacija
    useEffect(() => {
        fetch("http://localhost:8080/reservations/all")
            .then(res => res.json())
            .then(data => {
                if (data && data.data && data.data.values) {
                    // Izbaci PENDING rezervacije
                    const filtrirane = data.data.values.filter(r => r.statusRezervacije !== "PENDING");
                    setRezervacije(filtrirane);
                }
            })
            .catch(err => console.error("Greška pri učitavanju rezervacija:", err));
    }, []);

    // 🔹 Filtriranje rezervacija po statusu
    const filtriraneRezervacije = rezervacije.filter(r =>
        filterStatus === "sve" ? true : r.statusRezervacije === filterStatus
    );

    // 🔹 Brisanje rezervacije
    const handleDelete = async (idRezervacija) => {
        if (!window.confirm("Da li želite da obrišete ovu rezervaciju?")) return;

        try {
            const res = await fetch("http://localhost:8080/reservations/delete", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(idRezervacija)
            });

            if (res.ok) {
                alert("Rezervacija uspešno obrisana!");
                setRezervacije(prev => prev.filter(r => r.idRezervacija !== idRezervacija));
            } else {
                alert("Greška pri brisanju rezervacije.");
            }
        } catch (err) {
            console.error(err);
            alert("Došlo je do greške prilikom brisanja.");
        }
    };

    // 🔹 Dodavanje nove rezervacije
    const handleAdd = async () => {
        try {
            const res = await fetch("http://localhost:8080/reservations/add", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(novaRezervacija)
            });

            if (res.ok) {
                alert("Rezervacija uspešno dodata!");
                setShowModal(false);
                // Ponovno učitavanje rezervacija
                const refreshed = await fetch("http://localhost:8080/reservations/all").then(r => r.json());
                const filtrirane = refreshed.data.values.filter(r => r.statusRezervacije !== "PENDING");
                setRezervacije(filtrirane);
            } else {
                alert("Greška pri dodavanju rezervacije.");
            }
        } catch (err) {
            console.error(err);
            alert("Došlo je do greške pri dodavanju rezervacije.");
        }
    };

    return (
        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "space-between" }}>
            <NavBarRecepcionar />

            <div style={{
                backgroundImage: `url(${pattern})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                minHeight: "100vh",
                padding: "40px"
            }}>
                <h2 style={{
                    textAlign: "center",
                    color: "white",
                    backgroundColor: "rgba(226, 108, 255, 0.7)",
                    padding: "15px 30px",
                    borderRadius: "10px",
                    display: "inline-block",
                    marginBottom: "30px"
                }}>
                    Sve rezervacije
                </h2>

                {/* 🔹 Filter */}
                <div style={{ textAlign: "center", marginBottom: "20px" }}>
                    <select
                        value={filterStatus}
                        onChange={(e) => setFilterStatus(e.target.value)}
                        style={{ padding: "10px", borderRadius: "5px", marginRight: "10px" }}
                    >
                        <option value="sve">Sve</option>
                        <option value="ODOBRENA">Odobrene</option>
                        <option value="ODBIJENA">Odbijene</option>
                        <option value="ZAVRSENA">Završene</option>
                    </select>

                    <button
                        onClick={() => setShowModal(true)}
                        style={{
                            padding: "10px 15px",
                            borderRadius: "5px",
                            backgroundColor: "#9d3dd5",
                            color: "white",
                            border: "none",
                            cursor: "pointer"
                        }}
                    >
                        Dodaj rezervaciju
                    </button>
                </div>

                {/* 🔹 Prikaz rezervacija */}
                <div style={{ display: "flex", flexWrap: "wrap", gap: "20px", justifyContent: "center" }}>
                    {filtriraneRezervacije.length > 0 ? (
                        filtriraneRezervacije.map((rez) => (
                            <div key={rez.idRezervacija} style={{
                                backgroundColor: "rgba(255,255,255,0.9)",
                                width: "300px",
                                borderRadius: "10px",
                                padding: "15px",
                                textAlign: "left",
                                boxShadow: "0 2px 10px rgba(0,0,0,0.2)"
                            }}>
                                <p><strong>ID rezervacije:</strong> {rez.idRezervacija}</p>
                                <p><strong>Gost:</strong> {rez.gost?.ime} {rez.gost?.prezime}</p>
                                <p><strong>Soba:</strong> {rez.soba?.brojSobe}</p>
                                <p><strong>Od:</strong> {rez.datumPocetka}</p>
                                <p><strong>Do:</strong> {rez.datumZavrsetka}</p>
                                <p><strong>Status:</strong> {rez.statusRezervacije}</p>

                                <div style={{ display: "flex", justifyContent: "flex-end" }}>
                                    <button
                                        onClick={() => handleDelete(rez.idRezervacija)}
                                        style={{
                                            backgroundColor: "#e3dd61",
                                            border: "none",
                                            borderRadius: "5px",
                                            padding: "5px 10px",
                                            cursor: "pointer"
                                        }}
                                    >
                                        Obriši
                                    </button>
                                </div>
                            </div>
                        ))
                    ) : (
                        <p style={{ color: "white", fontSize: "18px" }}>Nema dostupnih rezervacija.</p>
                    )}
                </div>
            </div>

            {/* 🔹 Modal za dodavanje rezervacije */}
            {showModal && (
                <div style={{
                    position: "fixed", top: 0, left: 0, width: "100%", height: "100%",
                    backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center"
                }}>
                    <div style={{
                        backgroundColor: "white", padding: "20px", borderRadius: "10px", width: "400px"
                    }}>
                        <h3>Nova rezervacija</h3>

                        <label>Datum početka:</label>
                        <input type="date"
                            value={novaRezervacija.datumPocetka}
                            onChange={(e) => setNovaRezervacija({ ...novaRezervacija, datumPocetka: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>Datum završetka:</label>
                        <input type="date"
                            value={novaRezervacija.datumZavrsetka}
                            onChange={(e) => setNovaRezervacija({ ...novaRezervacija, datumZavrsetka: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>ID gosta:</label>
                        <input type="number"
                            value={novaRezervacija.idGost}
                            onChange={(e) => setNovaRezervacija({ ...novaRezervacija, idGost: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>ID sobe:</label>
                        <input type="number"
                            value={novaRezervacija.idSoba}
                            onChange={(e) => setNovaRezervacija({ ...novaRezervacija, idSoba: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <div style={{ display: "flex", justifyContent: "flex-end" }}>
                            <button onClick={() => setShowModal(false)} style={{ marginRight: "10px" }}>Otkaži</button>
                            <button onClick={handleAdd} style={{ backgroundColor: "purple", color: "white" }}>Sačuvaj</button>
                        </div>
                    </div>
                </div>
            )}

            <Footer />
        </div>
    );
}
